Implement a 4-bit adder with full adders. The output sum should include
the overflow bit.

module TopModule (
  input [3:0] x,
  input [3:0] y,
  output [4:0] sum
);module TopModule (
  input [3:0] x,
  input [3:0] y,
  output [4:0] sum
);

  wire [3:0] carry;

  // Full adder for each bit
  full_adder fa0 (.a(x[0]), .b(y[0]), .cin(1'b0), .sum(sum[0]), .cout(carry[0]));
  full_adder fa1 (.a(x[1]), .b(y[1]), .cin(carry[0]), .sum(sum[1]), .cout(carry[1]));
  full_adder fa2 (.a(x[2]), .b(y[2]), .cin(carry[1]), .sum(sum[2]), .cout(carry[2]));
  full_adder fa3 (.a(x[3]), .b(y[3]), .cin(carry[2]), .sum(sum[3]), .cout(carry[3]));

  // Overflow bit is the carry out of the most significant bit
  assign sum[4] = carry[3];

endmodule

// Full adder module
module full_adder (
  input a,
  input b,
  input cin,
  output sum,
  output cout
);

  assign sum = a ^ b ^ cin;
  assign cout = (a & b) | (cin & (a ^ b));

endmodule

Create a 4-bit wide, 256-to-1 multiplexer. The 256 4-bit inputs are all
