Build a circuit that has two 3-bit inputs that computes the bitwise-OR of
the two vectors, the logical-OR of the two vectors, and the inverse (NOT)
of both vectors. Place the inverse of b in the upper half of out_not
(i.e., bits [5:3]), and the inverse of a in the lower half.

module TopModule (
  input [2:0] a,
  input [2:0] b,
  output [2:0] out_or_bitwise,
  output out_or_logical,
  output [5:0] out_not
);module TopModule (
  input [2:0] a,
  input [2:0] b,
  output [2:0] out_or_bitwise,
  output out_or_logical,
  output [5:0] out_not
);

  // Compute bitwise OR of a and b
  assign out_or_bitwise = a | b;

  // Compute logical OR of a and b
  assign out_or_logical = (a != 3'b000) || (b != 3'b000);

  // Compute inverse of a and b
  assign out_not[2:0] = ~a;  // Lower half: inverse of a
  assign out_not[5:3] = ~b;  // Upper half: inverse of b

endmodule

