Build a 4-digit BCD (binary-coded decimal) counter. Each decimal digit is
encoded using 4 bits: q[3:0] is the ones digit, q[7:4] is the tens digit,
etc. For digits [3:1], also output an enable signal indicating when each
of the upper three digits should be incremented. Include a synchronous
active-high reset.

module TopModule (
  input clk,
  input reset,
  output [3:1] ena,
  output reg [15:0] q
);module TopModule (
  input clk,
  input reset,
  output [3:1] ena,
  output reg [15:0] q
);

  // Internal signals for BCD digits
  reg [3:0] ones, tens, hundreds, thousands;

  // Synchronous reset
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      ones <= 4'b0000;
      tens <= 4'b0000;
      hundreds <= 4'b0000;
      thousands <= 4'b0000;
    end else begin
      // Increment the ones digit
      if (ones == 4'b1001) begin
        ones <= 4'b0000;
        // Increment the tens digit
        if (tens == 4'b1001) begin
          tens <= 4'b0000;
          // Increment the hundreds digit
          if (hundreds == 4'b1001) begin
            hundreds <= 4'b0000;
            // Increment the thousands digit
            if (thousands == 4'b1001) begin
              thousands <= 4'b0000;
            end
          end
        end
      end else begin
        ones <= ones + 1;
      end
    end
  end

  // Output the BCD digits
  assign q = {thousands, hundreds, tens, ones};

  // Enable signals for upper digits
  assign ena[3] = (ones == 4'b1001);
  assign ena[2] = (tens == 4'b1001);
  assign ena[1] = (hundreds == 4'b1001);

endmodule

